import { Text } from "@justkits/ui/Texts";

import { styles } from "./styles.css";

type Props = {
  variant: "icon" | "text";
  size?: number;
} & React.SVGProps<SVGSVGElement>;

export function JustkitsLogo({
  variant = "icon",
  size = 36,
  ...props
}: Readonly<Props>) {
  if (variant === "text") {
    return (
      <span className={styles.logo} style={{ gap: 0.5 * size }}>
        <Logo {...props} size={size} />
        <Text
          variant="hero"
          style={{
            marginTop: 0.15 * size,
            fontSize: size,
            lineHeight: 1.2 * size,
          }}
        >
          Justkits
        </Text>
      </span>
    );
  }

  return <Logo {...props} size={size} />;
}

